-- Insert 24 new jump-height exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Split-Squat Jump to Stick', 'split-squat-jump-to-stick', 'The athlete performs Split-Squat Jump to Stick as a quality-first jump-height drill, emphasizing links unilateral leg drive to vertical projection while demanding front-leg braking and pelvis control on the finish.', 'ADVANCED', 8, 3, 1, NULL, 90, 65, 'Split-Squat Jump to Stick is a split-stance vertical foundation exercise for jumping athletes who need more vertical height. It targets links unilateral leg drive to vertical projection while demanding front-leg braking and pelvis control on the finish.', 'Primary subrole: jump/throw explosive power. Coach Split-Squat Jump to Stick for jump-height transfer: Drive up, switch or land split, and own the front leg. Keep the dose small enough that every rep preserves speed, posture, contact quality, and pain-free control.', 'Drive up, switch or land split, and own the front leg.', 'Split-stance vertical foundation', 'output', 'jump_throw_explosive_power', 'split_squat_jump_to_stick', '{"primary_joint_actions":["jump pattern","land pattern","squat pattern","brace pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":3,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb, '{"movement_description":"The athlete performs Split-Squat Jump to Stick as a quality-first jump-height drill, emphasizing links unilateral leg drive to vertical projection while demanding front-leg braking and pelvis control on the finish.","setup":["Set up in a clear open floor area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Drive up, switch or land split, and own the front leg.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Drive up, switch or land split, and own the front leg.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb),
  ('Approach Jump Penultimate Stick', 'approach-jump-penultimate-stick', 'The athlete performs Approach Jump Penultimate Stick as a quality-first jump-height drill, emphasizing teaches athletes to convert approach speed into a stable penultimate/takeoff shape before adding maximal jump height.', 'INTERMEDIATE', 8, 3, 1, NULL, 60, 55, 'Approach Jump Penultimate Stick is a approach takeoff foundation exercise for jumping athletes who need more vertical height. It targets teaches athletes to convert approach speed into a stable penultimate/takeoff shape before adding maximal jump height.', 'Primary subrole: locomotion/sprint mechanics. Coach Approach Jump Penultimate Stick as approach/takeoff skill, not conditioning. Use clear rhythm goals, short reps, and immediate feedback.', 'Tall approach, lower on the penultimate, then stick the takeoff shape.', 'Approach takeoff foundation', 'movement_intelligence', 'locomotion_sprint_mechanics', 'approach_jump_penultimate_stick', '{"primary_joint_actions":["locomote pattern","jump pattern","land pattern","brace pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":2,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb, '{"movement_description":"The athlete performs Approach Jump Penultimate Stick as a quality-first jump-height drill, emphasizing teaches athletes to convert approach speed into a stable penultimate/takeoff shape before adding maximal jump height.","setup":["Set up in a clear cones area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Tall approach, lower on the penultimate, then stick the takeoff shape.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Tall approach, lower on the penultimate, then stick the takeoff shape.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb),
  ('Lateral Line Pogo', 'lateral-line-pogo', 'The athlete performs Lateral Line Pogo as a quality-first jump-height drill, emphasizing builds frontal-plane elastic control for athletes who plant, gather, or jump from lateral movement.', 'INTERMEDIATE', 8, 2, 3, 5, 60, 65, 'Lateral Line Pogo is a lateral ankle stiffness exercise for jumping athletes who need more vertical height. It targets builds frontal-plane elastic control for athletes who plant, gather, or jump from lateral movement.', 'Primary subrole: elastic stiffness plyometric rudiments. Coach Lateral Line Pogo for jump-height transfer: Quick side-to-side contacts; stay tall and quiet. Keep the dose small enough that every rep preserves speed, posture, contact quality, and pain-free control.', 'Quick side-to-side contacts; stay tall and quiet.', 'Lateral ankle stiffness', 'output', 'elastic_stiffness_plyometric_rudiments', 'lateral_line_pogo', '{"primary_joint_actions":["jump pattern","land pattern","locomote pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":1,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb, '{"movement_description":"The athlete performs Lateral Line Pogo as a quality-first jump-height drill, emphasizing builds frontal-plane elastic control for athletes who plant, gather, or jump from lateral movement.","setup":["Set up in a clear line area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Quick side-to-side contacts; stay tall and quiet.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Quick side-to-side contacts; stay tall and quiet.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb),
  ('Jump Rope Low Bounce', 'jump-rope-low-bounce', 'The athlete performs Jump Rope Low Bounce as a quality-first jump-height drill, emphasizing uses rope rhythm to keep contacts short, posture tall, and elastic timing repeatable without high amplitudes.', 'INTERMEDIATE', 8, 2, 3, 5, 60, 65, 'Jump Rope Low Bounce is a elastic rhythm exercise for jumping athletes who need more vertical height. It targets uses rope rhythm to keep contacts short, posture tall, and elastic timing repeatable without high amplitudes.', 'Primary subrole: elastic stiffness plyometric rudiments. Coach Jump Rope Low Bounce for jump-height transfer: Let the rope set the rhythm; bounce low and smooth. Keep the dose small enough that every rep preserves speed, posture, contact quality, and pain-free control.', 'Let the rope set the rhythm; bounce low and smooth.', 'Elastic rhythm', 'output', 'elastic_stiffness_plyometric_rudiments', 'jump_rope_low_bounce', '{"primary_joint_actions":["jump pattern","land pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":1,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb, '{"movement_description":"The athlete performs Jump Rope Low Bounce as a quality-first jump-height drill, emphasizing uses rope rhythm to keep contacts short, posture tall, and elastic timing repeatable without high amplitudes.","setup":["Set up in a clear jump rope area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Let the rope set the rhythm; bounce low and smooth.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Let the rope set the rhythm; bounce low and smooth.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb),
  ('Wall Ankling Pogo', 'wall-ankling-pogo', 'The athlete performs Wall Ankling Pogo as a quality-first jump-height drill, emphasizing the wall support lets athletes feel active foot strike and lower-leg stiffness with less balance noise.', 'INTERMEDIATE', 8, 2, 3, 5, 60, 65, 'Wall Ankling Pogo is a supported sprint stiffness exercise for jumping athletes who need more vertical height. It targets the wall support lets athletes feel active foot strike and lower-leg stiffness with less balance noise.', 'Primary subrole: elastic stiffness plyometric rudiments. Coach Wall Ankling Pogo for jump-height transfer: Push the wall, strike under the hips, stay stacked. Keep the dose small enough that every rep preserves speed, posture, contact quality, and pain-free control.', 'Push the wall, strike under the hips, stay stacked.', 'Supported sprint stiffness', 'output', 'elastic_stiffness_plyometric_rudiments', 'wall_ankling_pogo', '{"primary_joint_actions":["jump pattern","land pattern","brace pattern"],"primary_tissues":[],"primary_motor_control_demands":["stacked ribs and pelvis","active foot tripod","knee tracks over toes","controlled landing or finish","Pain-free squat/hinge/landing pattern","Can follow cues and stop on command","Can keep posture and breathing under the planned speed"],"postural_shape":"stacked ribs and pelvis","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":1,"expression_quality":"Explosive contacts should look fast, quiet, tall, and repeatable; strength-support reps should look strong and technically consistent.","contraindication_flags":["Current lower-limb pain with jumping","Recent acute ankle/knee/hip injury without clearance","Inability to land or brace safely"]}'::jsonb, '{"movement_description":"The athlete performs Wall Ankling Pogo as a quality-first jump-height drill, emphasizing the wall support lets athletes feel active foot strike and lower-leg stiffness with less balance noise.","setup":["Set up in a clear wall area with enough space for safe takeoff and landing. Explain the rep count, finish rule, and stop signal before starting."],"execution_steps":["Start in the prescribed stance with eyes up, ribs stacked, and feet active.","Create the intended dip, approach, contact, or load without rushing the setup.","Execute with the cue: Push the wall, strike under the hips, stay stacked.","Land, rebound, or finish exactly as prescribed; reset fully before the next rep.","End the set as soon as speed, height, rhythm, alignment, or pain-free control degrades."],"coach_cues":["Push the wall, strike under the hips, stay stacked.","Quiet feet","Tall posture","Full reset","Fast intent without fatigue chasing"],"quality_gate":["No pain or guarding","Foot, knee, and hip stay aligned","Contact is quiet and fast for jump work","Landing or finish is controlled","Next rep would look as good as the current rep"],"common_faults":["Chasing height after landing quality drops","Letting knees collapse inward","Losing trunk position or arm timing","Turning the drill into a conditioning station"],"regressions":["Lower amplitude or box height","Fewer contacts or reps","Planned version before reactive version","Two-leg version before single-leg version"],"progressions":["Add approach speed only after shape is owned","Increase amplitude before adding complexity","Progress from stick to rebound when landing is reliable","Use light external load only if speed remains crisp"]}'::jsonb),
