INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), 'primary', m.slot, pos.order_index,
  COALESCE(m.freshness_required, TRUE), COALESCE(m.fatigue_sensitivity, 5), COALESCE(m.fatigue_cost, 3),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 2), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('split-squat-jump-to-stick', 'output', 'split_squat_jump_to_stick', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('approach-jump-penultimate-stick', 'movement_intelligence', 'approach_jump_penultimate_stick', 5, TRUE, 4, 2, 3, 2, 'moderate'),
  ('lateral-line-pogo', 'output', 'lateral_line_pogo', 5, TRUE, 5, 3, 3, 1, 'high'),
  ('jump-rope-low-bounce', 'output', 'jump_rope_low_bounce', 5, TRUE, 5, 3, 3, 1, 'high'),
  ('wall-ankling-pogo', 'output', 'wall_ankling_pogo', 5, TRUE, 5, 3, 3, 1, 'high'),
  ('repeat-vertical-jump-tall-posture', 'output', 'repeat_vertical_jump_tall_posture', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('countermovement-jump-rebound', 'output', 'countermovement_jump_rebound', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('low-hurdle-hop-to-stick', 'output', 'low_hurdle_hop_to_stick', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('low-hurdle-pogo-continuous', 'output', 'low_hurdle_pogo_continuous', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('continuous-low-hurdle-hop', 'output', 'continuous_low_hurdle_hop', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('depth-drop-to-vertical-rebound', 'output', 'depth_drop_to_vertical_rebound', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('depth-jump-to-rebound', 'output', 'depth_jump_to_rebound', 5, TRUE, 5, 4, 4, 5, 'high'),
  ('penultimate-step-pop-up', 'movement_intelligence', 'penultimate_step_pop_up', 5, TRUE, 4, 2, 3, 2, 'moderate'),
  ('two-step-rim-touch', 'output', 'two_step_rim_touch', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('volleyball-block-jump', 'output', 'volleyball_block_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('volleyball-approach-jump', 'output', 'volleyball_approach_jump', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('high-jump-takeoff-pop-up', 'output', 'high_jump_takeoff_pop_up', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('scissor-jump-takeoff-drill', 'movement_intelligence', 'scissor_jump_takeoff_drill', 5, TRUE, 4, 2, 3, 3, 'moderate'),
  ('alternating-bounds-for-height', 'output', 'alternating_bounds_for_height', 5, TRUE, 5, 4, 4, 4, 'high'),
  ('acceleration-pogo-run-in-to-vertical-jump', 'output', 'acceleration_pogo_run_in_to_vertical_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('trap-bar-jump', 'output', 'trap_bar_jump', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('loaded-squat-jump', 'output', 'loaded_squat_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('band-assisted-overspeed-jump', 'output', 'band_assisted_overspeed_jump', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('standing-calf-raise-isometric-hold', 'resilience', 'standing_calf_raise_isometric_hold', 5, FALSE, 3, 2, 3, 0, 'moderate')
) AS m(slug, phase_key, slot, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

INSERT INTO coaching.exercise_dosage_profile (
  exercise_id, profile_name, is_default, volume_unit, default_sets, default_reps,
  default_work_seconds, default_rest_seconds, default_distance, est_seconds_per_set, default_rpe_min, default_rpe_max
)
SELECT e.id, 'Default', TRUE, m.unit, m.sets, m.reps, m.work, m.rest, m.distance, m.est, m.rpe_min, m.rpe_max
FROM (VALUES
  ('split-squat-jump-to-stick', 'attempts', 3, 1, NULL, 90, NULL, 65, 7, 9),
  ('approach-jump-penultimate-stick', 'attempts', 3, 1, NULL, 60, NULL, 55, 5, 7),
  ('lateral-line-pogo', 'attempts', 2, 3, 5, 60, NULL, 65, 3, 5),
  ('jump-rope-low-bounce', 'attempts', 2, 3, 5, 60, NULL, 65, 3, 5),
  ('wall-ankling-pogo', 'attempts', 2, 3, 5, 60, NULL, 65, 3, 5),
  ('repeat-vertical-jump-tall-posture', 'attempts', 3, 2, NULL, 120, NULL, 75, 7, 9),
  ('countermovement-jump-rebound', 'attempts', 3, 2, NULL, 120, NULL, 75, 7, 9),
  ('low-hurdle-hop-to-stick', 'attempts', 3, 2, NULL, 120, NULL, 75, 7, 9),
  ('low-hurdle-pogo-continuous', 'attempts', 3, 2, NULL, 120, NULL, 75, 7, 9),
  ('continuous-low-hurdle-hop', 'attempts', 3, 2, NULL, 120, NULL, 75, 7, 9),
  ('depth-drop-to-vertical-rebound', 'attempts', 3, 1, NULL, 180, NULL, 95, 7, 9),
  ('depth-jump-to-rebound', 'attempts', 3, 1, NULL, 180, NULL, 95, 7, 9),
  ('penultimate-step-pop-up', 'attempts', 3, 1, NULL, 60, NULL, 55, 5, 7),
  ('two-step-rim-touch', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('volleyball-block-jump', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('volleyball-approach-jump', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('high-jump-takeoff-pop-up', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('scissor-jump-takeoff-drill', 'attempts', 3, 1, NULL, 60, NULL, 55, 5, 7),
  ('alternating-bounds-for-height', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('acceleration-pogo-run-in-to-vertical-jump', 'attempts', 3, 1, NULL, 120, NULL, 75, 7, 9),
  ('trap-bar-jump', 'attempts', 3, 2, NULL, 120, NULL, 75, 5, 7),
  ('loaded-squat-jump', 'attempts', 3, 2, NULL, 120, NULL, 75, 5, 7),
  ('band-assisted-overspeed-jump', 'attempts', 3, 2, NULL, 120, NULL, 75, 5, 7),
  ('standing-calf-raise-isometric-hold', 'attempts', 2, 1, 20, 60, NULL, 65, 5, 7)
) AS m(slug, unit, sets, reps, work, rest, distance, est, rpe_min, rpe_max)
JOIN coaching.exercise e ON e.slug = m.slug
WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_dosage_profile d WHERE d.exercise_id = e.id AND d.profile_name = 'Default');

