INSERT INTO coaching.exercise_regimen_rule (
  exercise_id, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures,
  counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning
)
SELECT e.id,
  COALESCE(m.can_be_daily, FALSE),
  COALESCE(m.weekly_max_frequency, 3),
  COALESCE(m.minimum_hours_between_hard_exposures, 24),
  COALESCE(m.counts_as_high_intensity, TRUE),
  COALESCE(m.counts_as_high_impact, FALSE),
  COALESCE(m.counts_as_neural, TRUE),
  COALESCE(m.counts_as_tissue_stress, TRUE),
  COALESCE(m.counts_as_conditioning, FALSE)
FROM (VALUES
  ('split-squat-jump-to-stick', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('approach-jump-penultimate-stick', TRUE, 4, 0, FALSE, FALSE, TRUE, TRUE, FALSE),
  ('lateral-line-pogo', FALSE, 3, 24, TRUE, FALSE, TRUE, FALSE, FALSE),
  ('jump-rope-low-bounce', FALSE, 3, 24, TRUE, FALSE, TRUE, FALSE, FALSE),
  ('wall-ankling-pogo', FALSE, 3, 24, TRUE, FALSE, TRUE, FALSE, FALSE),
  ('repeat-vertical-jump-tall-posture', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('countermovement-jump-rebound', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('low-hurdle-hop-to-stick', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('low-hurdle-pogo-continuous', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('continuous-low-hurdle-hop', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('depth-drop-to-vertical-rebound', FALSE, 1, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('depth-jump-to-rebound', FALSE, 1, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('penultimate-step-pop-up', TRUE, 4, 0, FALSE, FALSE, TRUE, TRUE, FALSE),
  ('two-step-rim-touch', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('volleyball-block-jump', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('volleyball-approach-jump', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('high-jump-takeoff-pop-up', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('scissor-jump-takeoff-drill', TRUE, 4, 0, FALSE, TRUE, TRUE, TRUE, FALSE),
  ('alternating-bounds-for-height', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('acceleration-pogo-run-in-to-vertical-jump', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('trap-bar-jump', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('loaded-squat-jump', FALSE, 2, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('band-assisted-overspeed-jump', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('standing-calf-raise-isometric-hold', TRUE, 4, 0, FALSE, FALSE, FALSE, TRUE, FALSE)
) AS m(slug, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures, counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning)
JOIN coaching.exercise e ON e.slug = m.slug
WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_regimen_rule r WHERE r.exercise_id = e.id);

